17	const PROCESSING_FEE = 5;
18	const BLOCK_SIZE = 3;
19	const RUNE_BLOCK_PREMIUM = 60;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
31	
32	const isRune = (item: Item): boolean => item.type === "rune";
33	
34	const isMainItem = (item: Item): boolean => !isRune(item);
35	
36	const RUNE_UNIT_PRICE = unitPriceFor("rune");
37	
38	const runeBasePremium = (runeCount: number): number =>
39	  runeCount === BLOCK_SIZE ? RUNE_BLOCK_PREMIUM : runeCount * RUNE_UNIT_PRICE;
40	
41	const sumUnitPrices = (items: Item[]): number =>
42	  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);
43	
44	const countRunes = (items: Item[]): number => items.filter(isRune).length;
45	
46	const totalBasePremium = (items: Item[]): number =>
47	  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));
48	
49	const policyModifiers = (policyBase: number): number =>
50	  FIRST_INSURANCE_RATE * policyBase;
51	
52	export const quote = (input: QuoteInput): number => {
53	  const policyBase = totalBasePremium(input.items);
54	  return Math.ceil(policyBase + policyModifiers(policyBase) + PROCESSING_FEE);
55	};
